     4→/**
     5→ * Job data pushed onto the BullMQ queue.
     6→ * `documentSourceId` is inherited from {@link BaseJobData} — no extra fields needed.
     7→ */
     8→export interface TextExtractionJobData extends BaseJobData {
     9→    // documentSourceId comes from BaseJobData
    10→}
    11→
    12→/**
    13→ * Unified result returned after the enrichment pipeline has run all registered
    14→ * enrichments against all text chunks of a document.
    15→ *
    16→ * Unlike the old `TextExtractionJobResult`, this type is open — it does not
    17→ * hard-code any specific enrichment names. Individual enrichment results are
    18→ * stored in {@link enrichmentResults} keyed by the enrichment's `name` property,
    19→ * so callers can access e.g. `result.enrichmentResults['requirements']` and
    20→ * `result.enrichmentResults['temporal']` while still being forwards-compatible
    21→ * with any future enrichments added to the registry.
    22→ */
    23→export interface PipelineJobResult extends BaseJobResult {
    24→    documentSourceId: string;
    25→    success: boolean;
    26→    processingTimeMs: number;
    27→    /** Number of Postgres text_chunks rows scanned */
    28→    chunksScanned: number;
    29→    /**
    30→     * Results from every registered enrichment, keyed by {@link ITextEnrichment.name}.
    31→     *
    32→     * Example:
    33→     * ```json
    34→     * {
    35→     *   "requirements": { "enrichmentName": "requirements", "extracted": 12, ... },
    36→     *   "temporal":     { "enrichmentName": "temporal",     "extracted": 4,  ... }
    37→     * }
    38→     * ```
    39→     */
    40→    enrichmentResults: Record<string, EnrichmentResult>;
    41→    metadata?: Record<string, unknown>;
    42→}
