     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { RequirementsRepository, RequirementData } from '@app/discovery-neo/requirements/requirements.repository';
     3→import { ITextEnrichment, TextChunk, EnrichmentContext, EnrichmentResult } from '../text-enrichment.interface';
     4→import { RequirementExtractor } from './requirement.extractor';
     5→import { ExtractedRequirement } from './requirement.types';
     6→
     7→/** Typed result specific to the requirements enrichment. */
     8→export interface RequirementEnrichmentResult extends EnrichmentResult {
     9→    enrichmentName: 'requirements';
    10→    /** Count per keyword: { must: N, shall: N, will: N } */
    11→    keywordBreakdown: Record<string, number>;
    12→}
    13→
    14→/**
    15→ * Text enrichment definition for normative requirement extraction.
    16→ *
    17→ * Implements {@link ITextEnrichment} and is registered with the
    18→ * {@link TextEnrichmentManager} at module initialisation time.
    19→ *
    20→ * Responsibilities:
    21→ *  1. Iterate the supplied chunks and delegate to the pure stateless
    22→ *     {@link RequirementExtractor} for sentence-level keyword matching.
    23→ *  2. Persist all extracted requirements to Neo4j via {@link RequirementsRepository}.
    24→ *  3. Return a typed {@link RequirementEnrichmentResult} for pipeline aggregation.
    25→ *
    26→ * This class intentionally has no knowledge of Postgres — chunk fetching is
    27→ * handled upstream by {@link EnrichmentPipeline}.
    28→ */
    29→@Injectable()
    30→export class RequirementEnrichment implements ITextEnrichment<RequirementEnrichmentResult> {
    31→    readonly name = 'requirements' as const;
    32→    readonly description = 'Extracts normative requirement sentences containing must / shall / will';
    33→
    34→    private readonly logger = new Logger(RequirementEnrichment.name);
    35→
    36→    constructor(private readonly requirementsRepository: RequirementsRepository) {}
    37→
    38→    async processChunks(
    39→        chunks: TextChunk[],
    40→        context: EnrichmentContext,
    41→    ): Promise<RequirementEnrichmentResult> {
    42→        const allRequirements: ExtractedRequirement[] = [];
    43→
    44→        for (const chunk of chunks) {
    45→            const text = chunk.text ?? '';
    46→            allRequirements.push(...RequirementExtractor.extract(text, chunk.id));
    47→        }
    48→
    49→        this.logger.log(
    50→            `[${context.documentSourceId}] Extracted ${allRequirements.length} requirement(s) ` +
    51→            `from ${chunks.length} chunk(s)`,
    52→        );
    53→
    54→        if (allRequirements.length > 0) {
    55→            const requirementData: RequirementData[] = allRequirements.map((req) => ({
    56→                id: req.id,
    57→                text: req.text,
    58→                keyword: req.keyword,
    59→                textGuid: req.sourceChunkId,
    60→            }));
    61→            await this.requirementsRepository.createRequirements(requirementData);
    62→        }
    63→
    64→        return {
    65→            enrichmentName: 'requirements',
    66→            extracted: allRequirements.length,
    67→            keywordBreakdown: this.buildKeywordBreakdown(allRequirements),
    68→            metadata: {
    69→                chunksScanned: chunks.length,
    70→            },
    71→        };
    72→    }
    73→
    74→    private buildKeywordBreakdown(requirements: ExtractedRequirement[]): Record<string, number> {
    75→        return requirements.reduce<Record<string, number>>((acc, req) => {
    76→            acc[req.keyword] = (acc[req.keyword] ?? 0) + 1;
    77→            return acc;
    78→        }, {});
    79→    }
    80→}
    81→

