     9→// Job interfaces extending base interfaces
    10→export interface EmbeddingJobData extends BaseJobData {
    11→    batchSize?: number;
    12→}
    13→
    14→// Export the result interface from domain service for compatibility
    15→export { EmbeddingJobResult };
    16→
    17→@Injectable()
    18→@UseInterceptors(AuditingInterceptor)
    19→export class EmbeddingQueueService extends BaseQueueService<EmbeddingJobData, EmbeddingJobResult> {
    20→    // Define abstract properties from base class
    21→    protected readonly queueName = 'embedding-enrichment-dedicated';
    22→    protected readonly jobName = 'process-embeddings';
    23→    protected readonly defaultRedisDb = '2';
    24→
    25→    constructor(
    26→        redisConnection: RedisConnectionService,
    27→        loggingStorage: LoggingStorage,
    28→        private embeddingService: EmbeddingService,
    29→        private auditingService: AuditingService,
    30→    ) {
    31→        super(redisConnection, loggingStorage);
    32→    }
    33→
    34→    // Abstract method implementation
    35→    protected getRedisDbEnvVar(): string | undefined {
    36→        return process.env.REDIS_EMBEDDING_DB;
    37→    }
    38→
    39→    async onModuleInit() {
    40→        // Domain service doesn't need initialization - just call parent
    41→        await super.onModuleInit();
    42→    }
    43→
    44→    // Abstract method implementation - pure delegation to domain service
    45→    protected async processJob(data: EmbeddingJobData): Promise<EmbeddingJobResult> {
    46→        return await this.embeddingService.processEmbeddingJob(
    47→            data.documentSourceId,
    48→            data.batchSize
    49→        );
    50→    }
    51→
    52→    // Public API methods (now creates its own milestones following discovery-core pattern)
    53→    async addEmbeddingJob(
    54→        documentSourceId: string, 
    55→        batchSize?: number,
    56→        neo4jCredentials?: Record<string, unknown>,
    57→        transactionId?: string,
    58→        isRetry?: boolean,
    59→        requestData?: Record<string, unknown>
    60→    ): Promise<string> {
    61→        this.logger.verbose(`Adding embedding job for document ${documentSourceId}`);
    62→
    63→        // Create milestone for this embedding operation
    64→        const milestoneId = await this.auditingService.createMilestone(
    65→            'enrichment-embedding',
    66→            {
    67→                documentSourceId: documentSourceId,
    68→                batchSize: batchSize,
    69→                isRetry: isRetry,
    70→                methodName: 'addEmbeddingJob',
    71→                className: 'EmbeddingQueueService'
    72→            }
    73→        );
    74→
    75→        try {
    76→            // Input validation
    77→            if (batchSize !== undefined && (typeof batchSize !== 'number' || batchSize <= 0)) {
    78→                throw new Error('batchSize must be a positive number');
    79→            }
    80→            
    81→            const jobData: EmbeddingJobData = {
    82→                documentSourceId,
    83→                batchSize,
    84→                neo4jCredentials,
    85→                transactionId,
    86→                isRetry,
    87→                requestData
    88→            };
    89→            
    90→            const jobId = await this.createJob(jobData);
    91→            
    92→            await this.auditingService.complete(milestoneId, {
    93→                success: true,
    94→                jobId: jobId,
    95→                documentSourceId: documentSourceId
    96→            });
    97→            
    98→            return jobId;
    99→        } catch (error) {
   100→            await this.auditingService.fail(milestoneId, error);
   101→            throw error;
   102→        }
   103→    }
   104→
   105→    // Method to wait for job completion (synchronous behavior)
   106→    async processEmbeddingJobAndWait(
   107→        documentSourceId: string, 
   108→        batchSize?: number,
   109→        neo4jCredentials?: Record<string, unknown>,
   110→        transactionId?: string,
   111→        isRetry?: boolean,
   112→        requestData?: Record<string, unknown>
   113→    ): Promise<EmbeddingJobResult> {
   114→        this.logger.log(`🚀 Starting embedding processing for document: ${documentSourceId}`);
   115→        
   116→        // Add the job to the queue
   117→        const jobId = await this.addEmbeddingJob(
   118→            documentSourceId,
   119→            batchSize,
   120→            neo4jCredentials,
   121→            transactionId,
   122→            isRetry,
   123→            requestData
   124→        );
   125→
   126→        // Wait for completion using base class method
   127→        return await this.waitForJobCompletion(jobId);
   128→    }
   129→
   130→    async onModuleDestroy() {
   131→        // Domain service doesn't need cleanup - just call parent
   132→        await super.onModuleDestroy();
   133→    }
   134→
   135→    // All other methods (getQueueStatus, getJobDetails, cancelJob, etc.) 
   136→    // are inherited from BaseQueueService
   137→}
