     1→import {
     2→  Injectable,
     3→  NestInterceptor,
     4→  ExecutionContext,
     5→  CallHandler,
     6→  Logger,
     7→} from '@nestjs/common';
     8→import { Reflector } from '@nestjs/core';
     9→import { Observable, Subscription } from 'rxjs';
    10→import { tap, catchError } from 'rxjs/operators';
    11→import { throwError } from 'rxjs';
    12→import { AuditingService } from './auditing.service';
    13→import { TRANSACTIONAL_KEY } from './transactional.decorator';
    14→
    15→@Injectable()
    16→export class AuditingInterceptor implements NestInterceptor {
    17→  private readonly logger = new Logger(AuditingInterceptor.name);
    18→
    19→  constructor(
    20→    private readonly reflector: Reflector,
    21→    private readonly auditingService: AuditingService,
    22→  ) {}
    23→
    24→  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    25→    const options = this.reflector.get(TRANSACTIONAL_KEY, context.getHandler());
    26→
    27→    if (!options) {
    28→      return next.handle();
    29→    }
    30→
    31→    const { category } = options;
    32→
    33→    return new Observable((observer) => {
    34→      // Track the inner subscription so the teardown function can clean it up
    35→      // if the outer Observable is unsubscribed (e.g. client disconnects).
    36→      let innerSubscription: Subscription | undefined;
    37→
    38→      const teardown = () => innerSubscription?.unsubscribe();
    39→
    40→      this.auditingService
    41→        .createRequestAudit(category)
    42→        .then((auditId) => {
    43→          const request = context.switchToHttp().getRequest();
    44→          request.auditId = auditId;
    45→          request.isAsyncAudit = options.async;
    46→          this.logger.debug(
    47→            `[AUDIT] REQUEST created: id=${auditId}, category=${category}`,
    48→          );
    49→
    50→          // Both async and sync paths share the same audit lifecycle:
    51→          // tap → complete on success, catchError → fail on error.
    52→          // The `async` flag is stored on the request for downstream consumers
    53→          // (e.g. AsyncTransactionHelper) to decide how to handle the result;
    54→          // the interceptor itself does not need to branch on it.
    55→          innerSubscription = next
    56→            .handle()
    57→            .pipe(
    58→              tap(() => {
    59→                if (auditId) {
    60→                  this.auditingService.complete(auditId).catch((err) => {
    61→                    this.logger.error(`Failed to complete audit: ${err.message}`);
    62→                  });
    63→                }
    64→              }),
    65→              catchError((error) => {
    66→                if (auditId) {
    67→                  this.auditingService.fail(auditId, error).catch((err) => {
    68→                    this.logger.error(`Failed to fail audit: ${err.message}`);
    69→                  });
    70→                }
    71→                return throwError(() => error);
    72→              }),
    73→            )
    74→            .subscribe({
    75→              next: (value) => observer.next(value),
    76→              error: (error) => observer.error(error),
    77→              complete: () => observer.complete(),
    78→            });
    79→        })
    80→        .catch((err) => {
    81→          this.logger.error(`Failed to create REQUEST audit: ${err.message}`);
    82→          // Audit creation failed — still serve the request, just without auditing.
    83→          innerSubscription = next.handle().subscribe({
    84→            next: (value) => observer.next(value),
    85→            error: (error) => observer.error(error),
    86→            complete: () => observer.complete(),
    87→          });
    88→        });
    89→
    90→      return teardown;
    91→    });
    92→  }
    93→}
