     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { AuditingService } from './auditing.service';
     3→
     4→/**
     5→ * Utility service for managing asynchronous transaction operations.
     6→ * Provides helper methods to execute long-running operations while properly
     7→ * managing transaction state updates in the background.
     8→ * 
     9→ * Use this service within @Transactional(type, true) decorated endpoints
    10→ * to handle transaction completion/failure for async operations.
    11→ * 
    12→ * @example
    13→ * ```typescript
    14→ * @Injectable()
    15→ * export class DocumentService {
    16→ *   constructor(private asyncHelper: AsyncTransactionHelper) {}
    17→ * 
    18→ *   @Transactional('bulk_upload', true)
    19→ *   async bulkUpload(@AuditId() auditId: string, files: File[]) {
    20→ *     return this.asyncHelper.executeAsync(auditId, () => this.processBulkUpload(files));
    21→ *   }
    22→ * }
    23→ * ```
    24→ */
    25→@Injectable()
    26→export class AsyncTransactionHelper {
    27→    private readonly logger = new Logger(AsyncTransactionHelper.name);
    28→
    29→    constructor(private readonly transactionService: AuditingService) { }
    30→
    31→    /**
    32→     * Executes an async operation in the background while managing transaction state.
    33→     * Returns immediately with a success indicator, while the actual operation
    34→     * continues in the background. Transaction state is automatically updated
    35→     * based on the operation result.
    36→     * 
    37→     * Use this for fire-and-forget operations where the client doesn't need to wait
    38→     * for completion (e.g., bulk imports, background processing).
    39→     * 
    40→     * @param transactionId - The transaction ID to track (from @AuditId() decorator)
    41→     * @param operation - Async function to execute in the background
    42→     * @returns Promise resolving immediately with success status and transaction ID
    43→     * 
    44→     * @example
    45→     * ```typescript
    46→     * @Transactional('bulk_import', true)
    47→     * async startBulkImport(@AuditId() auditId: string, @Body() data: any[]) {
    48→     *   // Returns immediately, processing continues in background
    49→     *   return this.asyncHelper.executeAsync(auditId, async () => {
    50→     *     for (const item of data) {
    51→     *       await this.processItem(item);
    52→     *     }
    53→     *     return { processed: data.length };
    54→     *   });
    55→     * }
    56→     * ```
    57→     */
    58→    async executeAsync<T>(
    59→        transactionId: string,
    60→        operation: () => Promise<T>,
    61→        keepResult: boolean = true
    62→    ): Promise<{ success: boolean; transactionId: string }> {
    63→        try {
    64→            // Execute in background with comprehensive error handling
    65→            setImmediate(async () => {
    66→                try {
    67→                    this.logger.debug(`Starting async operation for transaction ${transactionId}`);
    68→                    const result = await operation();
    69→
    70→                    try {
    71→                        await this.transactionService.complete(
    72→                            transactionId,
    73→                            keepResult ? result as any : undefined
    74→                        );
    75→                        this.logger.debug(`Completed async operation for transaction ${transactionId}`);
    76→                    } catch (txError) {
    77→                        this.logger.error(`Failed to update transaction state for ${transactionId}:`, txError);
    78→                        // Try to mark as failed
    79→                        try {
    80→                            await this.transactionService.fail(transactionId, txError);
    81→                        } catch (failError) {
    82→                            this.logger.error(`Failed to mark transaction as failed for ${transactionId}:`, failError);
    83→                        }
    84→                    }
    85→                } catch (operationError) {
    86→                    this.logger.error(`Async operation failed for transaction ${transactionId}:`, operationError.message);
    87→                    try {
    88→                        await this.transactionService.fail(transactionId, operationError);
    89→                    } catch (txError) {
    90→                        this.logger.error(`Failed to update transaction state on error for ${transactionId}:`, txError);
    91→                    }
    92→                }
    93→            });
    94→
    95→            // Return immediately - this part can still throw if there's an immediate issue
    96→            return { success: true, transactionId };
    97→        } catch (immediateError) {
    98→            // If we can't even start the async operation, fail the transaction immediately
    99→            this.logger.error(`Failed to start async operation for transaction ${transactionId}:`, immediateError);
   100→            try {
   101→                await this.transactionService.fail(transactionId, immediateError);
   102→            } catch (txError) {
   103→                this.logger.error(`Failed to mark transaction as failed for ${transactionId}:`, txError);
   104→            }
   105→            throw immediateError; // Re-throw so interceptor can handle it
   106→        }
   107→    }
   108→
   109→    /**
   110→     * Executes an async operation while waiting for completion and managing transaction state.
   111→     * Unlike executeAsync, this method waits for the operation to complete before returning,
   112→     * making it suitable for operations where you need the result or want to handle errors
   113→     * synchronously.
   114→     * 
   115→     * Use this when you need to await the async operation result within an async transaction
   116→     * endpoint, but still want automatic transaction state management.
   117→     * 
   118→     * @param transactionId - The transaction ID to track (from @AuditId() decorator)
   119→     * @param operation - Async function to execute and await
   120→     * @returns Promise resolving with the operation result
   121→     * @throws Re-throws any errors from the operation after updating transaction state
   122→     * 
   123→     * @example
   124→     * ```typescript
   125→     * @Transactional('document_analysis', true)
   126→     * async analyzeDocument(@AuditId() auditId: string, @Body() doc: Document) {
   127→     *   // Waits for completion, returns analysis result
   128→     *   const analysis = await this.asyncHelper.executeAsyncTracked(auditId, async () => {
   129→     *     const processed = await this.processDocument(doc);
   130→     *     const analyzed = await this.analyzeContent(processed);
   131→     *     return { analysis: analyzed, processedAt: new Date() };
   132→     *   });
   133→     *   
   134→     *   // Can use the result immediately
   135→     *   return { success: true, analysis };
   136→     * }
   137→     * ```
   138→     */
   139→    async executeAsyncTracked<T>(
   140→        transactionId: string,
   141→        operation: () => Promise<T>,
   142→        keepResult: boolean = true
   143→    ): Promise<T> {
   144→        try {
   145→            this.logger.debug(`Starting tracked async operation for transaction ${transactionId}`);
   146→            const result = await operation();
   147→
   148→            await this.transactionService.complete(
   149→                transactionId,
   150→                keepResult ? result as any : undefined
   151→            );
   152→
   153→            this.logger.debug(`Completed tracked async operation for transaction ${transactionId}`);
   154→            return result;
   155→        } catch (error) {
   156→            this.logger.error(`Tracked async operation failed for transaction ${transactionId}:`, error);
   157→            await this.transactionService.fail(transactionId, error);
   158→            throw error;
   159→        }
   160→    }
   161→}
