     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { TextChunkRepository } from '@app/discovery-database';
     3→import { TextEnrichmentManager } from './text-enrichment-manager.service';
     4→import { EnrichmentContext, EnrichmentResult } from './text-enrichment.interface';
     5→import { PipelineJobResult } from './text-extraction.interface';
     6→
     7→/**
     8→ * Orchestrator for the text-enrichment pipeline.
     9→ *
    10→ * Replaces the old hardcoded `TextExtractionService`. Instead of knowing about
    11→ * specific enrichment types (requirements, temporal, etc.) this service:
    12→ *
    13→ *  1. Fetches all `text_chunks` rows for the document from Postgres (one round-trip).
    14→ *  2. Asks the {@link TextEnrichmentManager} for all registered enrichments.
    15→ *  3. Fans the same chunk array out to every enrichment concurrently.
    16→ *  4. Collects the results into a generic {@link PipelineJobResult} keyed by
    17→ *     each enrichment's `name`.
    18→ *
    19→ * Adding a new enrichment type is now purely additive:
    20→ *  - Create a class that implements {@link ITextEnrichment}.
    21→ *  - Register it with the manager in {@link TextExtractionModule.onModuleInit}.
    22→ *  - This class requires **zero** changes.
    23→ */
    24→@Injectable()
    25→export class EnrichmentPipeline {
    26→    private readonly logger = new Logger(EnrichmentPipeline.name);
    27→
    28→    constructor(
    29→        private readonly textChunkRepository: TextChunkRepository,
    30→        private readonly enrichmentManager: TextEnrichmentManager,
    31→    ) {
    32→        this.logger.log('EnrichmentPipeline initialized');
    33→    }
    34→
    35→    /**
    36→     * Main entry point — called by the queue worker.
    37→     *
    38→     * @param documentSourceId - The document to process.
    39→     * @returns A unified job result aggregating all registered enrichments.
    40→     */
    41→    async processJob(documentSourceId: string): Promise<PipelineJobResult> {
    42→        const startTime = Date.now();
    43→
    44→        try {
    45→            this.logger.log(`📝 ENRICHMENT PIPELINE: Document ${documentSourceId}`);
    46→
    47→            if (!documentSourceId) {
    48→                throw new Error('documentSourceId is required');
    49→            }
    50→
    51→            // Fetch text chunks once — shared across all enrichments
    52→            const chunks = await this.textChunkRepository.findBySourceDocument(documentSourceId);
    53→
    54→            if (!chunks || chunks.length === 0) {
    55→                this.logger.warn(`No text chunks found for document ${documentSourceId}`);
    56→                return this.buildEmptyResult(documentSourceId, startTime);
    57→            }
    58→
    59→            this.logger.log(`Found ${chunks.length} text chunk(s) for document ${documentSourceId}`);
    60→
    61→            const enrichments = this.enrichmentManager.getAll();
    62→
    63→            if (enrichments.length === 0) {
    64→                this.logger.warn('No enrichments are registered — pipeline has nothing to run');
    65→                return this.buildEmptyResult(documentSourceId, startTime, {
    66→                    message: 'No enrichments registered',
    67→                });
    68→            }
    69→
    70→            this.logger.log(
    71→                `Running ${enrichments.length} enrichment(s): [${this.enrichmentManager.getRegisteredNames().join(', ')}]`,
    72→            );
    73→
    74→            const context: EnrichmentContext = { documentSourceId };
    75→
    76→            // Fan out to all enrichments concurrently
    77→            const results = await Promise.all(
    78→                enrichments.map((enrichment) => enrichment.processChunks(chunks, context)),
    79→            );
    80→
    81→            // Index results by enrichment name for easy consumption
    82→            const enrichmentResults = results.reduce<Record<string, EnrichmentResult>>(
    83→                (acc, result) => {
    84→                    acc[result.enrichmentName] = result;
    85→                    return acc;
    86→                },
    87→                {},
    88→            );
    89→
    90→            const totalExtracted = results.reduce((sum, r) => sum + r.extracted, 0);
    91→
    92→            this.logger.log(
    93→                `✅ Pipeline complete for document ${documentSourceId} — ` +
    94→                `${totalExtracted} total item(s) extracted across ${enrichments.length} enrichment(s)`,
    95→            );
    96→
    97→            return {
    98→                documentSourceId,
    99→                success: true,
   100→                processingTimeMs: Date.now() - startTime,
   101→                chunksScanned: chunks.length,
   102→                enrichmentResults,
   103→            };
   104→        } catch (error) {
   105→            const errorMessage = error instanceof Error ? error.message : 'Unknown error';
   106→            this.logger.error(
   107→                `❌ Enrichment pipeline failed for ${documentSourceId}: ${errorMessage}`,
   108→                error instanceof Error ? error.stack : undefined,
   109→            );
   110→            throw error;
   111→        }
   112→    }
   113→
   114→    private buildEmptyResult(
   115→        documentSourceId: string,
   116→        startTime: number,
   117→        metadata?: Record<string, unknown>,
   118→    ): PipelineJobResult {
   119→        return {
   120→            documentSourceId,
   121→            success: true,
   122→            processingTimeMs: Date.now() - startTime,
   123→            chunksScanned: 0,
   124→            enrichmentResults: {},
   125→            metadata: metadata ?? { message: 'No text chunks to process' },
   126→        };
   127→    }
   128→}
   129→

