     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { ITextEnrichment } from './text-enrichment.interface';
     3→
     4→/**
     5→ * Central registry for text enrichment definitions.
     6→ *
     7→ * The {@link TextEnrichmentManager} is a lightweight in-memory store that
     8→ * decouples the pipeline orchestrator from any specific enrichment
     9→ * implementation. Enrichments register themselves (or are registered by the
    10→ * module) at startup; the pipeline then calls {@link getAll} to fan out work
    11→ * without ever naming a concrete class.
    12→ *
    13→ * Registration happens in {@link TextExtractionModule.onModuleInit} so that
    14→ * the NestJS DI container has already resolved all repository dependencies
    15→ * before enrichments are handed to the manager.
    16→ *
    17→ * @example
    18→ * ```typescript
    19→ * // TextExtractionModule.onModuleInit()
    20→ * this.enrichmentManager.register(this.requirementEnrichment);
    21→ * this.enrichmentManager.register(this.temporalEnrichment);
    22→ * ```
    23→ */
    24→@Injectable()
    25→export class TextEnrichmentManager {
    26→    private readonly logger = new Logger(TextEnrichmentManager.name);
    27→    private readonly registry = new Map<string, ITextEnrichment>();
    28→
    29→    /**
    30→     * Register an enrichment definition.
    31→     * If an enrichment with the same {@link ITextEnrichment.name} is already
    32→     * registered it will be overwritten and a warning will be logged.
    33→     *
    34→     * @param enrichment - The enrichment definition to register.
    35→     * @returns `this` to allow fluent chaining.
    36→     */
    37→    register(enrichment: ITextEnrichment): this {
    38→        if (this.registry.has(enrichment.name)) {
    39→            this.logger.warn(
    40→                `Enrichment '${enrichment.name}' is already registered and will be overwritten.`,
    41→            );
    42→        }
    43→        this.registry.set(enrichment.name, enrichment);
    44→        this.logger.log(`Registered enrichment: '${enrichment.name}' — ${enrichment.description}`);
    45→        return this;
    46→    }
    47→
    48→    /**
    49→     * Retrieve all registered enrichments in registration order.
    50→     */
    51→    getAll(): ITextEnrichment[] {
    52→        return [...this.registry.values()];
    53→    }
    54→
    55→    /**
    56→     * Retrieve a specific enrichment by name, or `undefined` if not found.
    57→     */
    58→    get(name: string): ITextEnrichment | undefined {
    59→        return this.registry.get(name);
    60→    }
    61→
    62→    /**
    63→     * Return the names of all registered enrichments.
    64→     * Useful for logging and health-check endpoints.
    65→     */
    66→    getRegisteredNames(): string[] {
    67→        return [...this.registry.keys()];
    68→    }
    69→
    70→    /**
    71→     * Whether an enrichment with the given name has been registered.
    72→     */
    73→    has(name: string): boolean {
    74→        return this.registry.has(name);
    75→    }
    76→}
