    26→export class TextExtractionQueueService extends BaseQueueService<
    27→    TextExtractionJobData,
    28→    PipelineJobResult
    29→> {
    30→    // -----------------------------------------------------------------------
    31→    // Abstract property implementations required by BaseQueueService
    32→    // -----------------------------------------------------------------------
    33→    protected readonly queueName = 'text-extraction-dedicated';
    34→    protected readonly jobName = 'process-text-extraction';
    35→    protected readonly defaultRedisDb = '6';
    36→
    37→    constructor(
    38→        redisConnection: RedisConnectionService,
    39→        loggingStorage: LoggingStorage,
