     1→import { randomUUID } from 'crypto';
     2→import { ExtractedRequirement } from './requirement.types';
     3→
     4→/**
     5→ * Regex that matches any of the three normative modal keywords as whole words.
     6→ * Case-insensitive. Used once per sentence to identify the first keyword present.
     7→ */
     8→const REQUIREMENT_KEYWORD_RE = /\b(must|shall|will)\b/i;
     9→
    10→/**
    11→ * Splits a text string into individual sentences.
    12→ *
    13→ * Strategy:
    14→ *  - Split on sentence-ending punctuation (. ! ?) followed by whitespace or end-of-string.
    15→ *  - Trim each candidate sentence.
    16→ *  - Discard empty strings.
    17→ */
    18→function splitIntoSentences(text: string): string[] {
    19→    return text
    20→        .split(/(?<=[.!?])\s+|(?<=[.!?])$/)
    21→        .map((s) => s.trim())
    22→        .filter((s) => s.length > 0);
    23→}
    24→
    25→/**
    26→ * Pure stateless extractor for normative requirements.
    27→ *
    28→ * Accepts a raw text string and the ID of the source chunk it came from.
    29→ * Returns an array of {@link ExtractedRequirement} objects — one per sentence
    30→ * that contains a modal keyword (must / shall / will).
    31→ *
    32→ * No NestJS dependencies; safe to call as a plain static method.
    33→ */
    34→export class RequirementExtractor {
    35→    /**
    36→     * @param text         - Raw text from a single document chunk.
    37→     * @param sourceChunkId - The Postgres `text_chunks.id` that produced this text.
    38→     * @returns Array of extracted requirements (may be empty).
    39→     */
    40→    static extract(text: string, sourceChunkId: string): ExtractedRequirement[] {
    41→        const sentences = splitIntoSentences(text);
    42→        const results: ExtractedRequirement[] = [];
    43→
    44→        for (const sentence of sentences) {
    45→            const match = REQUIREMENT_KEYWORD_RE.exec(sentence);
    46→            if (match) {
    47→                results.push({
    48→                    id: randomUUID(),
    49→                    text: sentence,
    50→                    keyword: match[1].toLowerCase() as 'must' | 'shall' | 'will',
    51→                    sourceChunkId,
    52→                });
    53→            }
    54→        }
    55→
    56→        return results;
    57→    }
    58→}
