     1→import * as chrono from 'chrono-node';
     2→import { TemporalEntity, TemporalEntityType } from './temporal.types';
     3→
     4→/**
     5→ * Pure stateless extractor for temporal entities.
     6→ *
     7→ * Uses chrono-node to parse date/time/duration/frequency spans from raw text.
     8→ * No NestJS dependencies; safe to call as a plain static method.
     9→ */
    10→export class TemporalExtractor {
    11→    static extractEntities(text: string): TemporalEntity[] {
    12→        const results = chrono.parse(text);
    13→        const entities: TemporalEntity[] = [];
    14→
    15→        results.forEach((result) => {
    16→            const entity = this.classifyAndBuildEntity(result, text);
    17→            if (entity) {
    18→                entities.push(entity);
    19→            }
    20→        });
    21→
    22→        return entities;
    23→    }
    24→
    25→    private static classifyAndBuildEntity(result: chrono.ParsedResult, originalText: string): TemporalEntity | null {
    26→        const type = this.classifyType(result);
    27→        if (!type) {
    28→            return null;
    29→        }
    30→
    31→        const start = result.start as any;
    32→        const end = (result.end || {}) as any;
    33→        const withScore = result as any;
    34→
    35→        return {
    36→            type,
    37→            literal: result.text,
    38→            startIndex: start.offset,
    39→            endIndex: end?.offset || start.offset + result.text.length,
    40→            confidence: withScore.score,
    41→            isoValue: this.getISOValue(result),
    42→            components: this.extractComponents(result),
    43→            metadata: {
    44→                refDate: result.refDate,
    45→            },
    46→        };
    47→    }
    48→
    49→    private static classifyType(
    50→        result: chrono.ParsedResult,
    51→    ): TemporalEntityType | null {
    52→        const start = result.start;
    53→        const end = result.end;
    54→
    55→        const hasYear = start.get('year') !== undefined;
    56→        const hasMonth = start.get('month') !== undefined;
    57→        const hasDay = start.get('day') !== undefined;
    58→        const hasHour = start.get('hour') !== undefined;
    59→        const hasMinute = start.get('minute') !== undefined;
    60→        const hasSecond = start.get('second') !== undefined;
    61→        const hasWeekday = start.get('weekday') !== undefined;
    62→
    63→        // if it has date and time...
    64→        if ((hasYear || hasMonth || hasDay || hasWeekday) && !(hasHour || hasMinute)) {
    65→            return 'datetime';
    66→        }
    67→
    68→        // if its only date...
    69→        if (hasYear || hasMonth || hasDay || hasWeekday) {
    70→            return 'date';
    71→        }
    72→
    73→        // if only time components...
    74→        if (hasHour || hasMinute || hasSecond) {
    75→            return 'time';
    76→        }
    77→
    78→        // if frequency...
    79→        const text = result.text.toLowerCase();
    80→        if (
    81→            text.includes('every') ||
    82→            text.includes('each') ||
    83→            text.includes('weekly') ||
    84→            text.includes('daily') ||
    85→            text.includes('monthly') ||
    86→            text.includes('yearly')
    87→        ) {
    88→            return 'frequency';
    89→        }
    90→
    91→        // if duration...
    92→        if (
    93→            text.includes('for') ||
    94→            text.includes('during') ||
    95→            text.includes('hours') ||
    96→            text.includes('days') ||
    97→            text.includes('weeks') ||
    98→            text.includes('months') ||
    99→            text.includes('years')
   100→        ) {
   101→            return 'duration';
   102→        }
   103→
   104→        return null;
   105→    }
   106→
   107→    private static extractComponents(result: chrono.ParsedResult) {
   108→        const start = result.start;
   109→
   110→        const toUndef = (v: number | null | undefined) => v === null ? undefined : v;
   111→
   112→        return {
   113→            year: toUndef(start.get('year')),
   114→            month: toUndef(start.get('month')),
   115→            day: toUndef(start.get('day')),
   116→            hour: toUndef(start.get('hour')),
   117→            minute: toUndef(start.get('minute')),
   118→            second: toUndef(start.get('second')),
   119→            weekday: toUndef(start.get('weekday')),
   120→            unit: this.extractTimeUnit(result.text) ?? undefined,
   121→            value: this.extractTimeValue(result.text) ?? undefined,
   122→        };
   123→    }
   124→
   125→    private static getISOValue(result: chrono.ParsedResult): string | null {
   126→        try {
   127→            const start = result.start;
   128→
   129→            // month day year ISO format
   130→            if (
   131→                start.get('year') !== undefined ||
   132→                start.get('month') !== undefined ||
   133→                start.get('day') !== undefined
   134→            ) {
   135→                const date = start.date();
   136→                return date.toISOString().split('T')[0]; // YYYY-MM-DD
   137→            }
   138→
   139→            // check if hour/minute
   140→            if (start.get('hour') !== undefined || start.get('minute') !== undefined) {
   141→                const date = start.date();
   142→                const hours = start.get('hour') || 0;
   143→                const minutes = start.get('minute') || 0;
   144→                const seconds = start.get('second') || 0;
   145→                return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
   146→            }
   147→
   148→            return null;
   149→        } catch {
   150→            return null;
   151→        }
   152→    }
   153→
   154→    private static extractTimeUnit(text: string): string | null {
   155→        const lowerText = text.toLowerCase();
   156→
   157→        if (lowerText.includes('second')) return 'seconds';
   158→        if (lowerText.includes('minute')) return 'minutes';
   159→        if (lowerText.includes('hour')) return 'hours';
   160→        if (lowerText.includes('day')) return 'days';
   161→        if (lowerText.includes('week')) return 'weeks';
   162→        if (lowerText.includes('month')) return 'months';
   163→        if (lowerText.includes('year')) return 'years';
   164→
   165→        return null;
   166→    }
   167→
   168→    private static extractTimeValue(text: string): number | null {
   169→        const match = text.match(/(\d+(\.\d+)?)/);
   170→        return match ? parseInt(match[1], 10) : null;
   171→    }
   172→}
