    55→    // -----------------------------------------------------------------------
    56→    // Public API
    57→    // -----------------------------------------------------------------------
    58→
    59→    /**
    60→     * Enqueue a text extraction job and return the job ID immediately without
    61→     * waiting for completion.
    62→     */
    63→    async addTextExtractionJob(
    64→        documentSourceId: string,
